import{_ as e,o as a,c as n,ag as o}from"./chunks/framework.1N8rnUr9.js";const c=JSON.parse('{"title":"Uninstallation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/uninstallation.md","filePath":"guide/uninstallation.md","lastUpdated":1775715475000}'),l={name:"guide/uninstallation.md"};function i(r,t,s,d,u,g){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="uninstallation" tabindex="-1">Uninstallation <a class="header-anchor" href="#uninstallation" aria-label="Permalink to &quot;Uninstallation&quot;">​</a></h1><p>This page explains how to properly remove TubeBay from your WordPress site and what happens to your data.</p><h2 id="deactivation-vs-uninstallation" tabindex="-1">Deactivation vs. Uninstallation <a class="header-anchor" href="#deactivation-vs-uninstallation" aria-label="Permalink to &quot;Deactivation vs. Uninstallation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>What Happens</th></tr></thead><tbody><tr><td><strong>Deactivate</strong></td><td>The plugin is disabled but your mappings, settings, and synced library are preserved. You can reactivate later without losing anything.</td></tr><tr><td><strong>Delete (Uninstall)</strong></td><td>The plugin is removed from your site. Whether your settings and mappings are deleted depends on your configuration.</td></tr></tbody></table><h2 id="controlling-data-removal" tabindex="-1">Controlling Data Removal <a class="header-anchor" href="#controlling-data-removal" aria-label="Permalink to &quot;Controlling Data Removal&quot;">​</a></h2><p>TubeBay gives you control over what happens when the plugin is deleted:</p><ol><li>Go to <strong>TubeBay &gt; Settings</strong> in your WordPress admin.</li><li>Select the <strong>Advanced</strong> tab.</li><li>Look for the <strong>&quot;Delete data on uninstall&quot;</strong> toggle.</li><li>Toggle it based on your preference:</li></ol><table tabindex="0"><thead><tr><th>Setting</th><th>Effect on Uninstall</th></tr></thead><tbody><tr><td><strong>Enabled</strong></td><td>All TubeBay data is permanently deleted: video mappings, connection credentials (API Keys/Tokens), and plugin settings.</td></tr><tr><td><strong>Disabled</strong> (default)</td><td>Data is preserved in the database even after the plugin is deleted. Useful if you plan to reinstall later or upgrade.</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">Data Deletion Is Permanent</p><p>When &quot;Delete data on uninstall&quot; is enabled, deleting the plugin will <strong>permanently remove</strong> all your product mappings and stored YouTube tokens. This cannot be undone.</p></div><h2 id="what-gets-deleted" tabindex="-1">What Gets Deleted <a class="header-anchor" href="#what-gets-deleted" aria-label="Permalink to &quot;What Gets Deleted&quot;">​</a></h2><p>When the plugin is uninstalled with data deletion enabled, the following is removed:</p><ul><li><strong>Video Mappings:</strong> All links between YouTube videos and WooCommerce products.</li><li><strong>YouTube Credentials:</strong> Your API Key or OAuth Refresh Token.</li><li><strong>Synced Library Cache:</strong> The local cache of your YouTube video metadata.</li><li><strong>Plugin Settings:</strong> Global configuration and player settings.</li></ul><h2 id="how-to-uninstall" tabindex="-1">How to Uninstall <a class="header-anchor" href="#how-to-uninstall" aria-label="Permalink to &quot;How to Uninstall&quot;">​</a></h2><ol><li>Go to <strong>Plugins</strong> in your WordPress admin.</li><li>Click <strong>Deactivate</strong> next to TubeBay.</li><li>Click <strong>Delete</strong> to remove the plugin.</li><li>If &quot;Delete data on uninstall&quot; was enabled, all data is now removed from your database.</li></ol>',14)])])}const p=e(l,[["render",i]]);export{c as __pageData,p as default};
